int main(void) {
    /* Unsigned wrap-around: well-defined */
    unsigned int u = UINT_MAX;
    printf("UINT_MAX:     %u\n", u);       /* 4294967295 */
    printf("UINT_MAX + 1: %u\n", u + 1);   /* 0 (wraps) */

    /* Signed overflow: UNDEFINED BEHAVIOR -- do NOT rely on this */
    /* The following line is technically UB, shown for illustration only */
    /* int s = INT_MAX;
       printf("%d\n", s + 1);  // UB! Could print anything */

    /* Safe signed overflow check */
    int a = INT_MAX;
    int b = 1;
    if (b > 0 && a > INT_MAX - b) {
        printf("Would overflow!\n");
    }

    /* Mixing signed and unsigned */
    int neg = -1;
    unsigned int pos = 1;
    if (neg < pos) {
        printf("Expected: -1 < 1\n");
    } else {
        printf("Surprise: -1 is converted to unsigned!\n");
    }
    /* Prints: Surprise: -1 is converted to unsigned! */
    /* Because -1 becomes UINT_MAX (4294967295) when converted to unsigned */

    return 0;
}

