/* extern declaration: defined in another file (or below) */
extern int global_count;

/* static global: only visible in this file */
static int file_private = 100;

void counter(void) {
    /* static local: persists between calls */
    static int count = 0;
    count++;
    printf("count = %d\n", count);
}

int global_count = 42; /* actual definition */

int main(void) {
    auto int x = 10; /* auto is default, rarely written */
    register int i;  /* hint to use register */

    counter(); /* count = 1 */
    counter(); /* count = 2 */
    counter(); /* count = 3 */

    printf("global_count = %d\n", global_count); /* 42 */
    printf("file_private = %d\n", file_private); /* 100 */

    /* &i would be illegal if compiler honors register */
    (void)x;
    (void)i;
    return 0;
}

