#include <stdio.h>

int main(void) {
    char a = 100, b = 100;

    /* a and b are promoted to int before multiplication */
    int result = a * b;  /* 10000, not overflow */
    printf("char * char = %d\n", result); /* 10000 */

    /* Without promotion, 100 * 100 = 10000 would overflow char (max 127) */

    /* Surprising case with unsigned char */
    unsigned char uc = 255;
    /* uc is promoted to int (255), then negated */
    if (-uc < 0) {
        printf("-uc is negative (promoted to int)\n"); /* This prints */
    }

    /* Shift operators: left operand is promoted */
    unsigned char mask = 0xFF;
    /* mask is promoted to int before shift */
    int shifted = mask << 24;
    printf("shifted = 0x%X\n", shifted); /* 0xFF000000 */

    /* sizeof promotion result */
    printf("sizeof(char + char) = %zu\n",
           sizeof(a + b)); /* sizeof(int), typically 4 */

    return 0;
}

