int main(void) {
    /* Representation error */
    double a = 0.1 + 0.2;
    printf("0.1 + 0.2 = %.20f\n", a); /* 0.30000000000000004... */
    printf("== 0.3? %d\n", a == 0.3); /* 0 (false!) */

    /* Epsilon comparison */
    double eps = 1e-9;
    if (fabs(a - 0.3) < eps) {
        printf("Approximately equal\n"); /* This prints */
    }

    /* Precision limits */
    float f = 16777216.0f;  /* 2^24 */
    printf("f     = %.1f\n", f);       /* 16777216.0 */
    printf("f + 1 = %.1f\n", f + 1.0f); /* 16777216.0! Lost precision */

    /* Special values */
    double inf = 1.0 / 0.0;
    double nan = 0.0 / 0.0;
    printf("1/0 = %f\n", inf);    /* inf */
    printf("0/0 = %f\n", nan);    /* nan or -nan */
    printf("nan == nan? %d\n", nan == nan); /* 0 (false!) */
    printf("isnan(nan)? %d\n", isnan(nan)); /* 1 (true) */

    return 0;
}

