#include <stdio.h>

int main(void) {
    char ch = 'A';
    printf("'A' as int: %d\n", ch);      /* 65 */
    printf("'A' + 1 = '%c'\n", ch + 1);  /* 'B' */

    /* Digit character to integer */
    char digit = '7';
    int num = digit - '0';  /* 55 - 48 = 7 */
    printf("'%c' -> %d\n", digit, num);

    /* Case conversion */
    char lower = 'a';
    char upper = lower - ('a' - 'A');  /* 97 - 32 = 65 = 'A' */
    printf("'%c' -> '%c'\n", lower, upper);

    /* Character literal is actually int in C */
    printf("sizeof('A') = %zu\n", sizeof('A'));  /* 4 (sizeof int!) */
    printf("sizeof(ch)  = %zu\n", sizeof(ch));   /* 1 (sizeof char) */

    /* Loop through alphabet */
    for (char c = 'a'; c <= 'z'; c++) {
        printf("%c", c);
    }
    printf("\n");

    return 0;
}

