#include <stdio.h>
#include <stdlib.h>

void print_value(void *ptr, char type) {
    switch (type) {
        case 'i': printf("%d\n", *(int *)ptr); break;
        case 'f': printf("%f\n", *(float *)ptr); break;
        case 'c': printf("%c\n", *(char *)ptr); break;
    }
}

int main(void) {
    int x = 42;
    float f = 3.14f;
    char c = 'A';

    void *ptr;

    /* Any pointer converts to void * implicitly */
    ptr = &x;
    print_value(ptr, 'i'); /* 42 */

    ptr = &f;
    print_value(ptr, 'f'); /* 3.140000 */

    ptr = &c;
    print_value(ptr, 'c'); /* A */

    /* malloc returns void * -- no cast needed in C */
    int *arr = malloc(5 * sizeof(int));
    if (arr) {
        arr[0] = 10;
        printf("arr[0] = %d\n", arr[0]);
        free(arr);
    }

    return 0;
}

