    printf("zeros[3] = %d\n", zeros[3]); /* 0 */

    /* Designated initializers (C99) */
    int d[5] = {[2] = 42, [4] = 99};
    /* d = {0, 0, 42, 0, 99} */
    printf("d[2]=%d d[4]=%d\n", d[2], d[4]);

    return 0;
}

